import{_ as e,o as r,c as a,ag as o}from"./chunks/framework.NIzFHKo_.js";const p=JSON.parse('{"title":"System Model","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/20_structure/20_system_model.md","filePath":"10_core/20_structure/20_system_model.md"}'),i={name:"10_core/20_structure/20_system_model.md"};function s(n,t,l,d,h,c){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="system-model" tabindex="-1">System Model <a class="header-anchor" href="#system-model" aria-label="Permalink to &quot;System Model&quot;">​</a></h1><p>QiAccess Start is the active system model.</p><blockquote><p>QiAccess is the portal. The map is the interface. The knowledge base is the memory behind each node.</p></blockquote><h2 id="core-runtime-parts" tabindex="-1">Core Runtime Parts <a class="header-anchor" href="#core-runtime-parts" aria-label="Permalink to &quot;Core Runtime Parts&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Part</th><th>Role</th></tr></thead><tbody><tr><td><strong>QiAccess Start</strong></td><td>Daily-use portal and navigation shell</td></tr><tr><td><strong>qiserver</strong></td><td>Protected runtime host for internal services</td></tr><tr><td><strong>QiNexus</strong></td><td>Storage backbone and folder discipline</td></tr><tr><td><strong>Wiki.js</strong></td><td>Readable knowledge base</td></tr><tr><td><strong>Repo docs</strong></td><td>Build doctrine, implementation notes, and technical references</td></tr><tr><td><strong>Memory</strong></td><td>Future continuity layer for timeline, decisions, and relationships</td></tr><tr><td><strong>Insights</strong></td><td>Future derived analysis layer</td></tr></tbody></table><h2 id="seven-root-navigation-contract" tabindex="-1">Seven-Root Navigation Contract <a class="header-anchor" href="#seven-root-navigation-contract" aria-label="Permalink to &quot;Seven-Root Navigation Contract&quot;">​</a></h2><p>The active portal has seven roots only:</p><ol><li>Home</li><li>Start</li><li>Capture</li><li>Knowledge</li><li>Memory</li><li>Insights</li><li>System</li></ol><h2 id="root-intent" tabindex="-1">Root Intent <a class="header-anchor" href="#root-intent" aria-label="Permalink to &quot;Root Intent&quot;">​</a></h2><ul><li><strong>Home</strong>: what needs attention now</li><li><strong>Start</strong>: what needs to be opened</li><li><strong>Capture</strong>: what must leave the head immediately</li><li><strong>Knowledge</strong>: what is known and where the source lives</li><li><strong>Memory</strong>: what happened, why it mattered, and how it connects</li><li><strong>Insights</strong>: what it means and what deserves notice</li><li><strong>System</strong>: how the stack runs, stays safe, and remains governable</li></ul><h2 id="system-subroutes" tabindex="-1">System Subroutes <a class="header-anchor" href="#system-subroutes" aria-label="Permalink to &quot;System Subroutes&quot;">​</a></h2><p>System owns nested surfaces for:</p><ul><li>access</li><li>server</li><li>storage</li><li>integrations</li><li>settings</li><li>blueprint</li><li>roadmap</li><li>security</li><li>diagnostics</li></ul><p>These are not top-level roots.</p><h2 id="current-operating-phase" tabindex="-1">Current Operating Phase <a class="header-anchor" href="#current-operating-phase" aria-label="Permalink to &quot;Current Operating Phase&quot;">​</a></h2><p>The current phase is stabilization and prototype validation.</p><p>The system is considered healthy when:</p><ol><li>the SPA builds and routes cleanly</li><li>Start opens real tools and services</li><li>Capture is fast enough to use without friction</li><li>Knowledge points to real docs and references</li><li>System exposes honest runtime and infrastructure visibility</li><li>Memory and Insights remain clearly marked when they are placeholders</li></ol><h2 id="source-of-truth-stack" tabindex="-1">Source of Truth Stack <a class="header-anchor" href="#source-of-truth-stack" aria-label="Permalink to &quot;Source of Truth Stack&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>Rule</th></tr></thead><tbody><tr><td>Canonical sources</td><td>owned documents, governed records, verified runtime facts</td></tr><tr><td>Knowledge</td><td>curated readable explanation of sources</td></tr><tr><td>Memory</td><td>continuity and relationship layer built from sources</td></tr><tr><td>Insights</td><td>derived interpretation that must link back to sources</td></tr></tbody></table><p>No derived layer becomes truth by itself.</p><h2 id="legacy-boundary" tabindex="-1">Legacy Boundary <a class="header-anchor" href="#legacy-boundary" aria-label="Permalink to &quot;Legacy Boundary&quot;">​</a></h2><p>Older QiOS, QiOne, tenant, client, and multi-product doctrine remains useful only where it still supports:</p><ul><li>identity discipline</li><li>metadata and naming controls</li><li>ADR-backed structural change</li><li>explicit security boundaries</li></ul><p>When it conflicts with the active portal, it belongs in quarantine rather than in the live system model.</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>QiAccess Start is Cody&#39;s cognitive front door.</p><p>It exists to:</p><ol><li>reduce cognitive load</li><li>capture what matters before it disappears</li><li>open the right tool fast</li><li>store knowledge in the right place</li><li>retrieve context when needed</li><li>surface patterns and insights</li><li>build toward AI-assisted wisdom</li></ol><h2 id="root-model" tabindex="-1">Root Model <a class="header-anchor" href="#root-model" aria-label="Permalink to &quot;Root Model&quot;">​</a></h2><p>QiAccess Start has seven top-level roots only:</p><ol><li>\\Home`n2. \\Start`n3. \\Capture`n4. \\Knowledge`n5. \\Memory`n6. \\Insights`n7. \\System`n</li></ol>',32)])])}const m=e(i,[["render",s]]);export{p as __pageData,m as default};
